                    <input type="checkbox" @bind="_compactMode" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="settings-card">
            <h6>Live Preview</h6>
            <div class="live-preview @(_theme == "Dark" ? "preview-dark" : "preview-light")"
                 style="font-size: @GetPreviewFontSize(); @(_compactMode ? "padding: 0.5rem; line-height: 1.2;" : "")">
                <div class="preview-header">
                    <strong>Sample Dashboard</strong>
                    <span class="preview-badge">@_theme Theme</span>
                </div>
                <p>This is a preview of your selected appearance settings.</p>
                <p>Font size: <strong>@_fontSize</strong> &middot; Language: <strong>@_language</strong> &middot; Compact: <strong>@(_compactMode ? "On" : "Off")</strong></p>
                <div class="preview-items">
                    <div class="preview-item">📊 Analytics</div>
                    <div class="preview-item">📁 Projects</div>
                    <div class="preview-item">👥 Team</div>
                </div>
            </div>
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

