@page "/settings"
@rendermode InteractiveServer
@using sv_865a74f62dec4e7e8d1a05370b7741ca.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)">
                <span class="sidebar-icon">@GetSectionIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast Message -->
            @if (_showToast)
            {
                <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                </div>
            }

            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfile()
                    break;
                case "Notifications":
                    @RenderNotifications()
                    break;
                case "Security":
                    @RenderSecurity()
                    break;
                case "Appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </div>
</div>

<!-- Revoke Session Confirmation Dialog -->
@if (_showRevokeDialog)
{
    <div class="modal-backdrop" @onclick="CancelRevoke">
        <div class="modal-dialog-custom" @onclick:stopPropagation="true">
            <h5>Revoke Session</h5>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> from <strong>@_sessionToRevoke?.Location</strong>?</p>
            <p class="text-muted">This will sign out the device immediately.</p>
            <div class="dialog-actions">
                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke Session</button>
            </div>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast state
    private bool _showToast;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile state
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Notifications state
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security state
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    // Appearance state
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] AvailableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Korean", "Portuguese"];

    private static readonly string[] AllChannelNames =
        ["announcements", "random", "off-topic", "watercooler", "design-feedback", "engineering", "general"];

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionDataAsync("Profile");
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (section == _activeSection) return;
        _activeSection = section;
        _loading = true;
        await LoadSectionDataAsync(section);
        _loading = false;
    }

    private async Task LoadSectionDataAsync(string section)
    {
        switch (section)
        {
            case "Profile":
                _savedProfile = await SettingsService.GetProfileAsync();
                ApplyProfileFromSaved();
                break;
            case "Notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _emailNotifications = prefs.EmailNotifications;
                _pushNotifications = prefs.PushNotifications;
                _weeklyDigest = prefs.WeeklyDigest;
                _allChannels = [.. AllChannelNames];
                _mutedChannels = [.. prefs.MutedChannels];
                break;
            case "Security":
                _security = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _security.TwoFactorEnabled;
                _passwordPanelOpen = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "Appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _theme = appearance.Theme;
                _fontSize = appearance.FontSize;
                _language = appearance.Language;
                _compactMode = appearance.CompactMode;
                break;
        }
    }

    private void ApplyProfileFromSaved()
    {
        if (_savedProfile is null) return;
        _displayName = _savedProfile.DisplayName;
        _email = _savedProfile.Email;
        _avatarUrl = _savedProfile.AvatarUrl;
        _bio = _savedProfile.Bio;
    }

    // --- Profile ---
    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        ApplyProfileFromSaved();
    }

    // --- Notifications ---
    private void ToggleChannel(string channel)
    {
        if (!_mutedChannels.Remove(channel))
            _mutedChannels.Add(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // --- Security ---
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }
        if (_newPassword.Length < 8)
        {
            await ShowToast("Password must be at least 8 characters.", isError: true);
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // --- Appearance ---
    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    // --- Toast ---
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private string GetPreviewFontSize() => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    // --- Render Fragments ---

    private RenderFragment RenderProfile() => __builder =>
    {
        <div class="section-header">
            <h3>Profile</h3>
            <p class="section-description">Manage your personal information and public profile.</p>
        </div>

        <div class="profile-layout">
