                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="() => ToggleChannel(channel)" />
                        <span>#@channel</span>
                    </label>
                }
            </div>
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
        </div>
    };

    private RenderFragment RenderSecurity() => __builder =>
    {
        <div class="section-header">
            <h3>Security</h3>
            <p class="section-description">Manage your password, two-factor authentication, and active sessions.</p>
        </div>

        <!-- Change Password -->
        <div class="settings-card">
