}

.password-fields {
    margin-top: 1rem;
    padding-top: 1rem;
    border-top: 1px solid #e0e0e0;
}

.status-badge {
    display: inline-block;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    margin-top: 0.25rem;
    font-weight: 500;
}

.status-on {
    background: #d1e7dd;
    color: #0f5132;
}

.status-off {
    background: #f8d7da;
    color: #842029;
}

/* Radio group */
.radio-group {
    display: flex;
    gap: 1.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    font-size: 0.95rem;
}

.radio-item input[type="radio"] {
    accent-color: #0d6efd;
}

/* Live Preview */
.live-preview {
    border-radius: 6px;
    padding: 1rem;
    transition: all 0.2s;
    border: 1px solid #ddd;
}

.preview-light {
    background: #fff;
    color: #333;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    background: #0d6efd22;
    color: #0d6efd;
}

.preview-dark .preview-badge {
    background: #6ea8fe33;
    color: #6ea8fe;
}

.live-preview p {
    margin: 0.3rem 0;
}

.preview-items {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.75rem;
}

.preview-item {
    padding: 0.4rem 0.75rem;
    border-radius: 6px;
    font-size: 0.9em;
}

.preview-light .preview-item {
    background: #f0f0f0;
}

.preview-dark .preview-item {
    background: #2a2a3e;
}

/* Modal / Dialog */
.modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.modal-dialog-custom {
    background: #fff;
    border-radius: 10px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0,0,0,0.2);
}

.modal-dialog-custom h5 {
    margin: 0 0 0.75rem;
}

.modal-dialog-custom p {
    margin: 0.25rem 0;
}

.dialog-actions {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    margin-top: 1rem;
}

/* Toast */
.toast-message {
    position: absolute;
    top: 1rem;
    right: 1.5rem;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    z-index: 100;
    animation: toast-in 0.25s ease-out;
