        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
        </div>
    };

    private RenderFragment RenderSecurity() => __builder =>
    {
        <div class="section-header">
            <h3>Security</h3>
            <p class="section-description">Manage your password, two-factor authentication, and active sessions.</p>
        </div>

        <!-- Change Password -->
        <div class="settings-card">
            <div class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <h6>Change Password</h6>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_security?.LastPasswordChange is not null)
            {
                <p class="text-muted last-changed">Last changed @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
            @if (_passwordPanelOpen)
            {
                <div class="password-fields">
                    <div class="form-group">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="settings-card">
            <div class="toggle-row">
                <div>
                    <h6 class="mb-0">Two-Factor Authentication</h6>
                    <span class="status-badge @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="settings-card">
            <h6>Active Sessions</h6>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-sm">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session == _security.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-success ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RequestRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions.</p>
            }
        </div>
    };

    private RenderFragment RenderAppearance() => __builder =>
    {
        <div class="section-header">
            <h3>Appearance</h3>
            <p class="section-description">Customize how the application looks and feels.</p>
        </div>

        <div class="settings-card">
            <h6>Theme</h6>
            <div class="radio-group">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <label class="radio-item">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </div>

        <div class="settings-card">
            <h6>Font Size</h6>
            <div class="radio-group">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <label class="radio-item">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </div>

        <div class="settings-card">
            <h6>Language</h6>
            <select class="form-select" @bind="_language">
                @foreach (var lang in AvailableLanguages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <div class="settings-card">
            <div class="toggle-row">
                <span>Compact Mode</span>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_compactMode" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="settings-card">
            <h6>Live Preview</h6>
            <div class="live-preview @(_theme == "Dark" ? "preview-dark" : "preview-light")"
                 style="font-size: @GetPreviewFontSize(); @(_compactMode ? "padding: 0.5rem; line-height: 1.2;" : "")">
                <div class="preview-header">
                    <strong>Sample Dashboard</strong>
                    <span class="preview-badge">@_theme Theme</span>
                </div>
                <p>This is a preview of your selected appearance settings.</p>
                <p>Font size: <strong>@_fontSize</strong> &middot; Language: <strong>@_language</strong> &middot; Compact: <strong>@(_compactMode ? "On" : "Off")</strong></p>
                <div class="preview-items">
                    <div class="preview-item">📊 Analytics</div>
                    <div class="preview-item">📁 Projects</div>
                    <div class="preview-item">👥 Team</div>
                </div>
            </div>
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
