            <p class="section-description">Manage your personal information and public profile.</p>
        </div>

        <div class="profile-layout">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" onerror="this.style.display='none'" />
                </div>
                <span class="avatar-url-label text-muted">@_avatarUrl</span>
            </div>

            <div class="profile-fields">
                <div class="form-group">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="form-group">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="form-group">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>

