    private RenderFragment RenderNotifications() => __builder =>
    {
        <div class="section-header">
            <h3>Notifications</h3>
            <p class="section-description">Choose how and when you want to be notified.</p>
        </div>

        <div class="settings-card">
            <h6>General</h6>
            <div class="toggle-row">
                <span>Email Notifications</span>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_emailNotifications" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
            <div class="toggle-row">
                <span>Push Notifications</span>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_pushNotifications" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
            <div class="toggle-row">
                <span>Weekly Digest</span>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_weeklyDigest" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <div class="settings-card">
            <h6>Muted Channels</h6>
            <p class="text-muted">Check channels you want to mute.</p>
