.settings-layout {
    display: flex;
    min-height: 80vh;
    gap: 0;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #e0e0e0;
    padding: 1rem 0;
    display: flex;
    flex-direction: column;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #333;
    font-size: 1.05rem;
    border-bottom: 1px solid #e0e0e0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.7rem 1.25rem;
    border: none;
    background: transparent;
    text-align: left;
    width: 100%;
    font-size: 0.95rem;
    color: #555;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #333;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content Area */
.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    position: relative;
    overflow-y: auto;
}

.section-header {
    margin-bottom: 1.5rem;
}

.section-header h3 {
    margin: 0 0 0.25rem;
    font-weight: 600;
}

.section-description {
    color: #6c757d;
    margin: 0;
}

/* Cards */
.settings-card {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
    margin-bottom: 1rem;
}

.settings-card h6 {
    margin: 0 0 0.75rem;
    font-weight: 600;
}

/* Profile */
.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    border: 3px solid #e0e0e0;
    overflow: hidden;
    background: #f0f0f0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-url-label {
    font-size: 0.75rem;
    max-width: 140px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    text-align: center;
}

.profile-fields {
    flex: 1;
}

/* Form */
.form-group {
    margin-bottom: 1rem;
}

.form-label {
    font-weight: 500;
    margin-bottom: 0.3rem;
    display: block;
    font-size: 0.9rem;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1rem;
}

/* Toggle Switch */
.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0;
}

.toggle-row + .toggle-row {
    border-top: 1px solid #f0f0f0;
}

.toggle-switch {
    position: relative;
    display: inline-block;
    width: 44px;
    height: 24px;
    margin: 0;
    cursor: pointer;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: #ccc;
    border-radius: 24px;
    transition: background 0.2s;
}

.toggle-slider::before {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    left: 3px;
    bottom: 3px;
    background: #fff;
    border-radius: 50%;
    transition: transform 0.2s;
}

.toggle-switch input:checked + .toggle-slider {
    background: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(20px);
}

/* Channels */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
    padding: 0.3rem 0;
    font-size: 0.95rem;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

/* Security */
.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
}

.expandable-header h6 {
    margin: 0;
}

.expand-icon {
    font-size: 0.8rem;
    color: #888;
}

.last-changed {
    font-size: 0.85rem;
    margin: 0.25rem 0 0;
}

.password-fields {
    margin-top: 1rem;
    padding-top: 1rem;
    border-top: 1px solid #e0e0e0;
}

.status-badge {
    display: inline-block;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    margin-top: 0.25rem;
    font-weight: 500;
}

.status-on {
    background: #d1e7dd;
    color: #0f5132;
}

.status-off {
    background: #f8d7da;
    color: #842029;
}

/* Radio group */
.radio-group {
    display: flex;
    gap: 1.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    font-size: 0.95rem;
}

.radio-item input[type="radio"] {
    accent-color: #0d6efd;
}

/* Live Preview */
.live-preview {
    border-radius: 6px;
    padding: 1rem;
    transition: all 0.2s;
    border: 1px solid #ddd;
}

.preview-light {
    background: #fff;
    color: #333;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    background: #0d6efd22;
    color: #0d6efd;
}

.preview-dark .preview-badge {
    background: #6ea8fe33;
    color: #6ea8fe;
}

.live-preview p {
    margin: 0.3rem 0;
}

.preview-items {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.75rem;
}

.preview-item {
    padding: 0.4rem 0.75rem;
    border-radius: 6px;
    font-size: 0.9em;
}

.preview-light .preview-item {
    background: #f0f0f0;
}

.preview-dark .preview-item {
    background: #2a2a3e;
}

/* Modal / Dialog */
.modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.modal-dialog-custom {
    background: #fff;
    border-radius: 10px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0,0,0,0.2);
}

.modal-dialog-custom h5 {
    margin: 0 0 0.75rem;
}

.modal-dialog-custom p {
    margin: 0.25rem 0;
}

.dialog-actions {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    margin-top: 1rem;
}

/* Toast */
.toast-message {
    position: absolute;
    top: 1rem;
    right: 1.5rem;
    padding: 0.6rem 1.25rem;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    z-index: 100;
    animation: toast-in 0.25s ease-out;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(-10px); }
    to { opacity: 1; transform: translateY(0); }
}

/* Loading */
.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 200px;
}

/* Table tweaks */
.table th {
    font-weight: 600;
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #888;
}

.table td {
    vertical-align: middle;
}

